# Test that CONFIG RESETSTAT resets cluster bus message stats

start_cluster 3 0 {tags {external:skip cluster}} {

test "Cluster should start ok" {
    wait_for_cluster_state ok
}

set primary1 [srv 0 "client"]
set primary2 [srv -1 "client"]

test "CONFIG RESETSTAT should reset cluster bus message stats" {
    # First reset to get a clean baseline
    $primary1 CONFIG RESETSTAT

    # After reset, cluster_stats_messages_received should be 0 or absent
    # We need to let some cluster messages flow, but after resetstat 
    # the stats should be zeroed.
    set info_after_reset [$primary1 CLUSTER INFO]

    # Verify that total messages received is 0 after reset
    # (or not present, meaning 0)
    if {[regexp {cluster_stats_messages_received:(\d+)} $info_after_reset -> count]} {
        assert_equal 0 $count
    }

    # Verify that total messages sent is 0 after reset  
    if {[regexp {cluster_stats_messages_sent:(\d+)} $info_after_reset -> count]} {
        assert_equal 0 $count
    }
}

} ;# start_cluster

